import { html, customElement, property } from '@umbraco-cms/backoffice/external/lit';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import { FormsInputFormElement } from '@umbraco-forms/components';

const elementName = "forms-folder-picker-multiple-property-editor";

@customElement(elementName)
export class FormsFolderPickerMultiplePropertyPickerElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  @property({ type: Array<String> })
  public value: Array<string> = [];

  async connectedCallback() {
    super.connectedCallback();
  }

  #onPickedFoldersChange(event: Event) {
    const target = event.target as FormsInputFormElement;
    this.value = target.selection;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  render() {
    return html`<forms-input-folder
      .selection=${this.value}
      .multiple=${true}
      @change=${this.#onPickedFoldersChange}
      slot="editor"></forms-input-folder>`;
  }
}

export default FormsFolderPickerMultiplePropertyPickerElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsFolderPickerMultiplePropertyPickerElement;
    }
}
